//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFTWIAndNSDCmd::MRFTWIAndNSDCmd() :
CATStateCommand ("MRFTWIAndNSDCmd", CATDlgEngOneShot)
{
	_TWIModified = CATFalse;
	this->Initialize();
	if (!!_pMRFTWINSDDlg)
	{
		_pMRFTWINSDDlg->BuildTWIFrame();
		_pMRFTWINSDDlg->BuildNSDFrame();
		_pMRFTWINSDDlg->BuildSurfaceList();
		_pMRFTWINSDDlg->SetVisibility(CATDlgShow);
		_pMRFTWINSDDlg->SetProfile4Widgets(false);

	}
}

//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFTWIAndNSDCmd::MRFTWIAndNSDCmd(CATBaseUnknown_var ispSpecObject) :
	CATStateCommand("MRFTWIAndNSDCmd", CATDlgEngOneShot)
{
	this->Initialize();
	if (!!_pMRFTWINSDDlg)
	{
		MRFITWISet_var spTWISet = ispSpecObject;
		MRFITWI_var spTWI = ispSpecObject;
		MRFINSD_var  spNSD = ispSpecObject;
		if (NULL_var != spTWISet)
		{
			_spTWISet = spTWISet;
			_pMRFTWINSDDlg->BuildTWIFrame();
			_pMRFTWINSDDlg->BuildSurfaceList();
			BuildTWIFrameOnEdit("TWISet");


			int noOfNSD = 0;
			spTWISet->GetNbOfNSDs(noOfNSD);
			if (noOfNSD > 0)
			{
				spTWISet->GetListOfNSDs(_spNSDList);
				_pMRFTWINSDDlg->BuildNSDFrame();
				BuildNSDFrameOnEdit("NSD");

			}


		}
		else if(NULL_var != spTWI)
		{
			_spTWI = ispSpecObject;
			if (!!_spTWI)
			{
				_spTWI->GetTWISet(_spTWISet);
				_pMRFTWINSDDlg->BuildTWIFrame();
				_pMRFTWINSDDlg->BuildSurfaceList();
				BuildTWIFrameOnEdit("TWI");

			}
		}
		else if (NULL_var != spNSD)
		{
			_spNSD = ispSpecObject;
			if (!!_spNSD)
			{
				_IsToCreateNSD = true;

				_pMRFTWINSDDlg->BuildNSDFrame();
				_pMRFTWINSDDlg->SetVisibility(CATDlgShow);
				BuildNSDFrameOnEdit("NSD");
			}
		}

		_pMRFTWINSDDlg->SetVisibility(CATDlgShow);
	}
}
//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFTWIAndNSDCmd::~MRFTWIAndNSDCmd()
{
	if (_Indication != NULL)
		_Indication->RequestDelayedDestruction();
	_Indication = NULL;

	if (NULL != _pEditor)
		_pEditor = NULL;

	if (!!_pViewer)
		_pViewer = NULL;

	if (NULL != _pHSO)
	{
		//_pHSO->Empty();
		_pHSO = NULL;
	}
	
	if (NULL != _pApplicationFrame)
	{
		//_pHSO->Empty();
		_pApplicationFrame = NULL;
	}

	if (NULL != _pTWISurfaceSelectorDialogAgent)
		_pTWISurfaceSelectorDialogAgent->RequestDelayedDestruction();
	_pTWISurfaceSelectorDialogAgent = NULL;

	if (NULL != _pTWICuttingPlaneDialogAgent)
		_pTWICuttingPlaneDialogAgent->RequestDelayedDestruction();
	_pTWICuttingPlaneDialogAgent = NULL;

	if (NULL != _pNSDTWISetDialogAgent)
		_pNSDTWISetDialogAgent->RequestDelayedDestruction();
	_pNSDTWISetDialogAgent = NULL;

	if (NULL != _pTWISurfaceSelectorPathElementAgent)
		_pTWISurfaceSelectorPathElementAgent->RequestDelayedDestruction();
	_pTWISurfaceSelectorPathElementAgent = NULL;

	if (NULL != _pTWICuttingPlanePathElementAgent)
		_pTWICuttingPlanePathElementAgent->RequestDelayedDestruction();
	_pTWICuttingPlanePathElementAgent = NULL;

	if (NULL != _pNSDTWISetPathElementAgent)
		_pNSDTWISetPathElementAgent->RequestDelayedDestruction();
	_pNSDTWISetPathElementAgent = NULL;

	if (NULL != _pMRFTWINSDDlg)
		_pMRFTWINSDDlg->RequestDelayedDestruction();
	_pMRFTWINSDDlg = NULL;	
	
	if (NULL != _pTWISurfaceListDialogAgent)
		_pTWISurfaceListDialogAgent->RequestDelayedDestruction();
	_pTWISurfaceListDialogAgent = NULL;
	
	if (NULL != _pTWISurfaceListCloseDialogAgent)
		_pTWISurfaceListCloseDialogAgent->RequestDelayedDestruction();
	_pTWISurfaceListCloseDialogAgent = NULL;

	if (NULL != _pCuttingPlanePathElement)
		_pCuttingPlanePathElement = NULL;

	if (NULL_var != _spCuttingPlane)
		_spCuttingPlane = NULL_var;

	int size = _pTWISurfacePathElementList.Size();
	if (size > 0)
	{
		for (int i = 1; i <= size; i++)
		{
			_pTWISurfacePathElementList[i] = NULL;
		}
		_pTWISurfacePathElementList.RemoveAll();
	}
	
	if (_spTWISurfaceList.Size() > 0)
		_spTWISurfaceList.RemoveAll();

	if (NULL != _pTWISetPathElement)
		_pTWISetPathElement = NULL;

	if (NULL_var != _spTWISet)
		_spTWISet = NULL_var;

	if (_SelectedCellList.Size() > 0)
		_SelectedCellList.RemoveAll();

	if (NULL != _pMRFTWIAndNSDServices)
		_pMRFTWIAndNSDServices->Release();  _pMRFTWIAndNSDServices = NULL;
}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFTWIAndNSDCmd::BuildGraph()
{
	if (!!_pMRFTWINSDDlg)
	{
		AddAnalyseNotificationCB(_pMRFTWINSDDlg, _pMRFTWINSDDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFTWIAndNSDCmd::ActionOK, NULL);
		AddAnalyseNotificationCB(_pMRFTWINSDDlg, _pMRFTWINSDDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFTWIAndNSDCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFTWINSDDlg, _pMRFTWINSDDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFTWIAndNSDCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFTWINSDDlg, _pMRFTWINSDDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFTWIAndNSDCmd::ActionOne, NULL);

		CATDlgCombo* pTWIProfileCombo = _pMRFTWINSDDlg->GetTWIProfileTypeCombo();
		if (NULL != pTWIProfileCombo)
		{
			AddAnalyseNotificationCB(pTWIProfileCombo, pTWIProfileCombo->GetComboSelectNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::OnProfileComboSelection, NULL);
		}

		CATDlgCombo* pNSDManufTypeCombo = _pMRFTWINSDDlg->GetNSDManufType();
		if (NULL != pNSDManufTypeCombo)
		{
			AddAnalyseNotificationCB(pNSDManufTypeCombo, pNSDManufTypeCombo->GetComboSelectNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::OnNSDManuFTypeComboSelection, NULL);
		}

		_pTWISurfaceSelectorDialogAgent = new CATDialogAgent("TWISurfaceSelectorDialogAgent");
		if (_pTWISurfaceSelectorDialogAgent)
		{
			CATDlgSelectorList * pTWISurfaceSelector = _pMRFTWINSDDlg->GetTWISurfaceSelector();
			if (NULL != pTWISurfaceSelector)
			{
				_pTWISurfaceSelectorDialogAgent->AcceptOnNotify(pTWISurfaceSelector, pTWISurfaceSelector->GetListSelectNotification());
			}
		}
		_pTWISurfaceSelectorPathElementAgent = new CATPathElementAgent("TWISurfaceSelectorPathElementAgent");
		if (_pTWISurfaceSelectorPathElementAgent)
		{
			CATListOfCATString ListSurfaces;
			ListSurfaces.Append("CATSurface");
			ListSurfaces.Append("CATI3DGeometricalElement");

			_pTWISurfaceSelectorPathElementAgent->SetOrderedTypeList(ListSurfaces);
			_pTWISurfaceSelectorPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pTWICuttingPlaneDialogAgent = new CATDialogAgent("TWICuttingPlaneDialogAgent");
		if (_pTWICuttingPlaneDialogAgent)
		{
			CATDlgSelectorList * pCtngPlaneSelector = _pMRFTWINSDDlg->GetTWICuttingPlaneSelector();
			if (NULL != pCtngPlaneSelector)
			{
				_pTWICuttingPlaneDialogAgent->AcceptOnNotify(pCtngPlaneSelector, pCtngPlaneSelector->GetListSelectNotification());
			}
		}
		_pTWICuttingPlanePathElementAgent = new CATPathElementAgent("TWICuttingPlanePathElementAgent");
		if (_pTWICuttingPlanePathElementAgent)
		{
			_pTWICuttingPlanePathElementAgent->AddOrderedElementType("CATI3DGeometricalElement");
			_pTWICuttingPlanePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pNSDTWISetDialogAgent = new CATDialogAgent("NSDTWISetDialogAgent");
		if (_pNSDTWISetDialogAgent)
		{
			CATDlgSelectorList * pNSDTWISetSelector = _pMRFTWINSDDlg->GetNSDTWISetSelector();
			if (NULL != pNSDTWISetSelector)
			{
				_pNSDTWISetDialogAgent->AcceptOnNotify(pNSDTWISetSelector, pNSDTWISetSelector->GetListSelectNotification());
			}
		}
		_pNSDTWISetPathElementAgent = new CATPathElementAgent("NSDTWISetPathElementAgent");
		if (_pNSDTWISetPathElementAgent)
		{
			_pNSDTWISetPathElementAgent->AddOrderedElementType("CATI3DGeometricalElement");
			_pNSDTWISetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pTWISurfaceListDialogAgent = new CATDialogAgent("TWISurfaceListDialogAgent");
		CATDlgPushButton * pViewSurfaceList = _pMRFTWINSDDlg->GetMultiSurfaceButton();
		if (NULL != _pTWISurfaceListDialogAgent && NULL != pViewSurfaceList)
		{
			_pTWISurfaceListDialogAgent->AcceptOnNotify(pViewSurfaceList, pViewSurfaceList->GetPushBActivateNotification());
		}
		
		_pTWISurfaceListCloseDialogAgent = new CATDialogAgent("TWISurfaceListCloseDialogAgent");
		CATDlgDialog* pSurfaceListDlg = _pMRFTWINSDDlg->GetSurfaceListDialog();
		if (NULL != _pTWISurfaceListCloseDialogAgent  && NULL != pSurfaceListDlg)
		{
			_pTWISurfaceListCloseDialogAgent->AcceptOnNotify(pSurfaceListDlg, pSurfaceListDlg->GetWindCloseNotification());
		}

		CATDlgMultiList* pSurfaceMultiList = _pMRFTWINSDDlg->GetSurfaceList();
		if (NULL != pSurfaceMultiList)
		{
			AddAnalyseNotificationCB(pSurfaceMultiList, pSurfaceMultiList->GetListSelectNotification(), (CATCommandMethod)& MRFTWIAndNSDCmd::SurfaceListSelect, NULL);

			CATDlgContextualMenu* pListCtxMenu = _pMRFTWINSDDlg->GetSurfaceListCtxMenu();
			if (NULL != pListCtxMenu)
			{
				AddAnalyseNotificationCB(pListCtxMenu, pListCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::BuildSurfaceListContextMenu, NULL);
			}
		}

		
			
		CATDialogState * pInitialState = GetInitialState("InitialState");
		pInitialState->AddDialogAgent(_pTWISurfaceSelectorDialogAgent);
		pInitialState->AddDialogAgent(_pTWICuttingPlaneDialogAgent);
		pInitialState->AddDialogAgent(_pNSDTWISetDialogAgent);
		pInitialState->AddDialogAgent(_pTWISurfaceListDialogAgent);
		pInitialState->AddDialogAgent(_pTWISurfaceListCloseDialogAgent);

		CATDialogState * pTWISurfaceState = AddDialogState("TWISurfaceState");
		pTWISurfaceState->AddDialogAgent(_pTWISurfaceSelectorDialogAgent);
		pTWISurfaceState->AddDialogAgent(_pTWISurfaceSelectorPathElementAgent);
		pTWISurfaceState->AddDialogAgent(_pTWICuttingPlaneDialogAgent);
		pTWISurfaceState->AddDialogAgent(_pNSDTWISetDialogAgent);
		pTWISurfaceState->AddDialogAgent(_pTWISurfaceListDialogAgent);

		CATDialogState * pTWISurfaceListState = AddDialogState("TWISurfaceListState");
		pTWISurfaceListState->AddDialogAgent(_pTWISurfaceSelectorDialogAgent);
		pTWISurfaceListState->AddDialogAgent(_pTWICuttingPlaneDialogAgent);
		pTWISurfaceListState->AddDialogAgent(_pNSDTWISetDialogAgent);
		pTWISurfaceListState->AddDialogAgent(_pTWISurfaceListDialogAgent);
		pTWISurfaceListState->AddDialogAgent(_pTWISurfaceListCloseDialogAgent);
		pTWISurfaceListState->AddDialogAgent(_pTWISurfaceSelectorPathElementAgent);

		CATDialogState * pTWICuttingPlaneState = AddDialogState("TWICuttingPlaneState");
		pTWICuttingPlaneState->AddDialogAgent(_pTWICuttingPlaneDialogAgent);
		pTWICuttingPlaneState->AddDialogAgent(_pTWICuttingPlanePathElementAgent);
		pTWICuttingPlaneState->AddDialogAgent(_pTWISurfaceSelectorDialogAgent);
		pTWICuttingPlaneState->AddDialogAgent(_pNSDTWISetDialogAgent);
		pTWICuttingPlaneState->AddDialogAgent(_pTWISurfaceListDialogAgent);

		CATDialogState * pNSDTWISetState = AddDialogState("NSDTWISetState");
		pNSDTWISetState->AddDialogAgent(_pTWISurfaceSelectorDialogAgent);
		pNSDTWISetState->AddDialogAgent(_pTWICuttingPlaneDialogAgent);
		pNSDTWISetState->AddDialogAgent(_pNSDTWISetDialogAgent);
		pNSDTWISetState->AddDialogAgent(_pNSDTWISetPathElementAgent);
		pNSDTWISetState->AddDialogAgent(_pTWISurfaceListDialogAgent);

		CATCommandClientData TWISurfaceData("TWISurface");
		AddTransition(pInitialState, pTWISurfaceState, IsOutputSetCondition(_pTWISurfaceSelectorDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWISurfaceData));
		AddTransition(pTWISurfaceState, pTWISurfaceState, IsOutputSetCondition(_pTWISurfaceSelectorDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWISurfaceData));
		AddTransition(pTWICuttingPlaneState, pTWISurfaceState, IsOutputSetCondition(_pTWISurfaceSelectorDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWISurfaceData));
		AddTransition(pNSDTWISetState, pTWISurfaceState, IsOutputSetCondition(_pTWISurfaceSelectorDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWISurfaceData));

		AddTransition(pTWISurfaceState, pTWISurfaceState, IsOutputSetCondition(_pTWISurfaceSelectorPathElementAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnObjectSelection, NULL, NULL, TWISurfaceData));
		AddTransition(pTWISurfaceListState, pTWISurfaceListState, IsOutputSetCondition(_pTWISurfaceSelectorPathElementAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnObjectSelection, NULL, NULL, TWISurfaceData));

		CATCommandClientData TWICuttingPlaneData("TWICuttingPlane");
		AddTransition(pInitialState, pTWICuttingPlaneState, IsOutputSetCondition(_pTWICuttingPlaneDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWICuttingPlaneData));
		AddTransition(pTWISurfaceState, pTWICuttingPlaneState, IsOutputSetCondition(_pTWICuttingPlaneDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWICuttingPlaneData));
		AddTransition(pTWICuttingPlaneState, pTWICuttingPlaneState, IsOutputSetCondition(_pTWICuttingPlaneDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWICuttingPlaneData));
		AddTransition(pNSDTWISetState, pTWICuttingPlaneState, IsOutputSetCondition(_pTWICuttingPlaneDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, TWICuttingPlaneData));

		AddTransition(pTWICuttingPlaneState, pTWICuttingPlaneState, IsOutputSetCondition(_pTWICuttingPlanePathElementAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnObjectSelection, NULL, NULL, TWICuttingPlaneData));

		CATCommandClientData NSDTWISetData("NSDTWISet");
		AddTransition(pInitialState, pNSDTWISetState, IsOutputSetCondition(_pNSDTWISetDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, NSDTWISetData));
		AddTransition(pTWISurfaceState, pNSDTWISetState, IsOutputSetCondition(_pNSDTWISetDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, NSDTWISetData));
		AddTransition(pTWICuttingPlaneState, pNSDTWISetState, IsOutputSetCondition(_pNSDTWISetDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, NSDTWISetData));
		AddTransition(pNSDTWISetState, pNSDTWISetState, IsOutputSetCondition(_pNSDTWISetDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnSelectorListSelected, NULL, NULL, NSDTWISetData));

		AddTransition(pNSDTWISetState, pNSDTWISetState, IsOutputSetCondition(_pNSDTWISetPathElementAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::OnObjectSelection, NULL, NULL, NSDTWISetData));

		AddTransition(pInitialState, pTWISurfaceListState, IsOutputSetCondition(_pTWISurfaceListDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::ViewSelectedSurfaceList));
		AddTransition(pTWISurfaceState, pTWISurfaceListState, IsOutputSetCondition(_pTWISurfaceListDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::ViewSelectedSurfaceList));
		AddTransition(pTWICuttingPlaneState, pTWISurfaceListState, IsOutputSetCondition(_pTWISurfaceListDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::ViewSelectedSurfaceList));
		AddTransition(pNSDTWISetState, pTWISurfaceListState, IsOutputSetCondition(_pTWISurfaceListDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::ViewSelectedSurfaceList));
		AddTransition(pTWISurfaceListState, pInitialState, IsOutputSetCondition(_pTWISurfaceListCloseDialogAgent), Action((ActionMethod)&MRFTWIAndNSDCmd::SurfaceListClose));

		CATDlgContextualMenu* pSufaceCtxMenu = _pMRFTWINSDDlg->GetTWISurfaceCtxMenu();
		if (NULL != pSufaceCtxMenu)
		{
			AddAnalyseNotificationCB(pSufaceCtxMenu, pSufaceCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::OnCtxMenu, TWISurfaceData);
		}

		CATDlgContextualMenu* pNSDTWISetCtxMenu = _pMRFTWINSDDlg->GetNSDTWISetCtxMenu();
		if (NULL != pNSDTWISetCtxMenu)
		{
			AddAnalyseNotificationCB(pNSDTWISetCtxMenu, pNSDTWISetCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::OnCtxMenu, NSDTWISetData );
		}

		CATDlgContextualMenu* pTWICtngPlaneCtxMenu = _pMRFTWINSDDlg->GetCuttingPlaneCtxMenu();
		if (NULL != pTWICtngPlaneCtxMenu)
		{
			AddAnalyseNotificationCB(pTWICtngPlaneCtxMenu, pTWICtngPlaneCtxMenu->GetVisibilityNotification(), (CATCommandMethod)&MRFTWIAndNSDCmd::OnCtxMenu, TWICuttingPlaneData);
		}	

		this->SetTWIModified();
		
	}
}

void MRFTWIAndNSDCmd::Initialize()
{
	_Indication = NULL;
	_pEditor = NULL;
	_pHSO = NULL;
	_pViewer = NULL;
	_pApplicationFrame = NULL;
	_spMechanicalPart = NULL_var;
	_pTWISurfaceSelectorDialogAgent = NULL;
	_pTWICuttingPlaneDialogAgent = NULL;
	_pNSDTWISetDialogAgent = NULL;
	_pTWISurfaceSelectorPathElementAgent = NULL;
	_pTWICuttingPlanePathElementAgent = NULL;
	_pNSDTWISetPathElementAgent = NULL;
	_pCuttingPlanePathElement = NULL;
	_spCuttingPlane = NULL_var;
	_pMRFTWINSDDlg = NULL;
	_pTWISurfacePathElementList.RemoveAll();
	_spTWISurfaceList.RemoveAll();
	_pTWISetPathElement = NULL;
	_spTWISet = NULL_var;
	_SelectedCellList.RemoveAll();
	_pTWISurfaceListDialogAgent = NULL;
	_pTWISurfaceListCloseDialogAgent = NULL;
	_pMRFTWIAndNSDServices = NULL;
	_spTWI = NULL_var;
	_IsToCreateNSD = FALSE;
	_dNSDManufactType = 0;
	_spNSD = NULL_var;
	_spNSDList.RemoveAll();
	_TWIProfile = 0;
	_pApplicationFrame = CATApplicationFrame::GetFrame();

	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		_spCBUOnCurrObject = oActivePath.NextFatherElement();

		if (NULL_var != _spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			_spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart && NULL_var == _spMechanicalPart)
			{
				_spMechanicalPart = piPrtPart;
				piPrtPart->Release();  piPrtPart = NULL;
			}
		}
	}
	_pViewer = CATViewer::GetCurrentViewer();

	_pMRFTWINSDDlg = new MRFTWIAndNSDDlg();

}
//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFTWIAndNSDCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (!_IsToCreateNSD)
		if (_TWIModified && ValidateTWIInputs())
		{
			CATDlgCombo* pTWIProfileCombo = _pMRFTWINSDDlg->GetTWIProfileTypeCombo();
			if (!!pTWIProfileCombo && CATDlgEnable == pTWIProfileCombo->GetSensitivity())
			{
				//_TWIProfile = pTWIProfileCombo->GetSelect();
				pTWIProfileCombo->SetSensitivity(CATDlgDisable);
			}

			//if (SUCCEEDED(CreateOrUpdatePointVent(_PointVentTypeIndex)))
			CreateOrUpdateTWISet();
			{
				_TWIModified = CATFalse;
			}

			CATDlgCheckButton* pCheckButtonNSD = _pMRFTWINSDDlg->GetNSDCheck();
			if (pCheckButtonNSD)
			{
				int state = pCheckButtonNSD->GetState();

				if (state == CATDlgCheck)
				{
					CreateOrUpdateNSd(_spTWISet);
				}


			}

		}

	if (_TWIModified)
	{

		CATDlgCheckButton* pCheckButtonNSD = _pMRFTWINSDDlg->GetNSDCheck();
		if (pCheckButtonNSD)
		{
			int state = pCheckButtonNSD->GetState();

			if (state == CATDlgCheck)
			{
				CreateOrUpdateNSd(_spNSD);
			}


		}


	}
	return;
}

void MRFTWIAndNSDCmd::ActionOK(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (_TWIModified)
	{
		ActionOne(ipCommand, ipNotification, iUsefulData);
	}
	this->RequestDelayedDestruction();

	return;
}

void MRFTWIAndNSDCmd::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	this->RequestDelayedDestruction();

	return ;
}

//Method is called when SelectorList is selected in dialog window
CATBoolean MRFTWIAndNSDCmd::OnSelectorListSelected(void* iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;
	CATString strAction(pstrAction);

	CATDialogAgent * pDialoAgent = NULL;
	CATPathElement * pPathElement = NULL;

	if (!!_pMRFTWINSDDlg)
		_pMRFTWINSDDlg->ClearOtherSelections(strAction);

	if (strAction == "TWISurface")
	{
		pDialoAgent = _pTWISurfaceSelectorDialogAgent;
	}
	else if (strAction == "TWICuttingPlane")
	{
		pDialoAgent = _pTWICuttingPlaneDialogAgent;
		pPathElement = _pCuttingPlanePathElement;
	}
	else if (strAction == "NSDTWISet")
	{
		pDialoAgent = _pNSDTWISetDialogAgent;
		pPathElement = _pTWISetPathElement;
	}

	if (NULL != _pHSO)
	{
		_pHSO->Empty();
		if (strAction != "TWISurface")
		{
			if (NULL != pPathElement && 0 == _pHSO->IsMember(pPathElement))
				_pHSO->AddElement(pPathElement);
		}
		else
		{
			int size = _pTWISurfacePathElementList.Size();
			if (size > 0)
			{
				int i = 1;
				while (i <= size)
				{
					pPathElement = _pTWISurfacePathElementList[i];
					if (NULL != pPathElement && 0 == _pHSO->IsMember(pPathElement))
						_pHSO->AddElement(pPathElement);						
					i++;
					pPathElement = NULL;
				}				
			}
		}		
	}

	if (!!pDialoAgent)
		pDialoAgent->InitializeAcquisition();

	return CATTrue;
}

//Method is called when object is selected with selector list being highlighted in dialog window
CATBoolean MRFTWIAndNSDCmd::OnObjectSelection(void* iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;
	CATString strAction(pstrAction);

	CATPathElementAgent * pPathElementAgent = NULL;
	CATPathElement * pPathElement = NULL;

	CATDlgSelectorList* pSelListOnObject = NULL;

	if (!!_pMRFTWINSDDlg)
		_pMRFTWINSDDlg->ClearOtherSelections(strAction);

	if (strAction == "TWISurface")
	{
		pPathElementAgent = _pTWISurfaceSelectorPathElementAgent;
	}
	else if (strAction == "TWICuttingPlane")
	{
		pPathElementAgent = _pTWICuttingPlanePathElementAgent;
	}
	else if (strAction == "NSDTWISet")
	{
		pPathElementAgent = _pNSDTWISetPathElementAgent;
	}

	if (!!pPathElementAgent)
	{
		pPathElement = pPathElementAgent->GetValue();
		if (NULL != pPathElement)
		{
			CATBaseUnknown_var spSelectedElement;
			CATUnicodeString strAlias = "";

			if (strAction == "TWISurface")
			{
				if (_pTWISurfacePathElementList.Locate(pPathElement) == 0)
				{
					FeaturizeTWISurfaceSelected(pPathElement, spSelectedElement);					
					if (_spTWISurfaceList.Locate(spSelectedElement) == 0)
					{
						_pTWISurfacePathElementList.Append(pPathElement);
						_spTWISurfaceList.Append(spSelectedElement);
					}					
					UpdateSurfaceMultiList();
				}
				else
				{
					spSelectedElement = pPathElement->CurrentElement();
				}
			}
			else if (strAction == "TWICuttingPlane")
			{
				spSelectedElement = pPathElement->CurrentElement();
				_pCuttingPlanePathElement = pPathElement;
				_spCuttingPlane = spSelectedElement;
				if (!ValidateSelectedSegmentCuttingPlane())
				{
					spSelectedElement = NULL_var;
					_pCuttingPlanePathElement = NULL;
					_spCuttingPlane = NULL_var;
					_pMRFTWINSDDlg->UpdateSelectorList(strAction, "No Cutting Plane selected ...");
				}
			}
			else if (strAction == "NSDTWISet")
			{
				spSelectedElement = pPathElement->CurrentElement();
				_pTWISetPathElement = pPathElement;
				_spTWISet = spSelectedElement;
			}
			if (NULL_var != spSelectedElement)
			{
				if (strAction == "TWISurface")
				{
					int size = _spTWISurfaceList.Size();
					CATUnicodeString strInt;
					strInt.BuildFromNum(size);

					strAlias = strInt + " Surfaces selected";
				}
				else
				{
					CATIAlias_var spAlias = spSelectedElement;
					if (NULL_var != spAlias)
					{
						strAlias = spAlias->GetAlias();
					}
				}
				_pMRFTWINSDDlg->UpdateSelectorList(strAction, strAlias);
				if (NULL != _pHSO)
				{
					_pHSO->Empty();
					if (0 == _pHSO->IsMember(pPathElement))
						_pHSO->AddElement(pPathElement);
				}
				_TWIModified = CATTrue;
			}
		}
		
		pPathElementAgent->InitializeAcquisition();
	}
		
	return CATTrue;
}
