void MRFTWIAndNSDCmd::FeaturizeTWISurfaceSelected(CATPathElement * ipPathElement, CATBaseUnknown_var & ospSelectedSurface)
{
	if (!!ipPathElement)
	{
		CATBaseUnknown_var spMainElement = ipPathElement->CurrentElement();
		CATCell_var spSelectedCell;
		CATBaseUnknown_var spLastElement;
		CATIMmiMechanicalFeature_var spMechanicalFeature;
		ipPathElement->InitToLeafElement();

		if (NULL_var != (spLastElement = ipPathElement->NextFatherElement()))
		{
			if (NULL_var != spLastElement)
			{
				spMechanicalFeature = spLastElement;

				if (NULL_var == spMechanicalFeature)
				{
					CATIMmiUseBRepAccess_var spBRepAccess = spLastElement;
					if (NULL_var != spBRepAccess)
					{
						spBRepAccess->GetBRepSelectingCell(spSelectedCell);
					}
					
					if (NULL_var != spSelectedCell && NULL_var != spMainElement)
					{
						int locate = _SelectedCellList.Locate(spSelectedCell);
						if (locate > 0 && locate <= _spTWISurfaceList.Size())
						{
							spMechanicalFeature = _spTWISurfaceList[locate];
						}
						else
						{
							_SelectedCellList.Append(spSelectedCell);
							MRFGenericUtils::FeaturizeSubElement(spSelectedCell, spMainElement, spMechanicalFeature);
						}
					}
				}
			}
		}
		if (NULL_var != spMechanicalFeature)
		{
			ospSelectedSurface = spMechanicalFeature;
		}
	}
}

