void MRFTWIAndNSDCmd::UpdateSurfaceMultiList()
{
	CATDlgMultiList * pMultiList = _pMRFTWINSDDlg->GetSurfaceList();
	if (NULL != pMultiList)
	{
		int child = pMultiList->GetLineCount();
		int size = _spTWISurfaceList.Size();

		for (int i = child; i < size; i++)
		{
			CATBaseUnknown_var spSurface = _spTWISurfaceList[i + 1];
			if (NULL_var != spSurface)
			{
				CATIAlias_var spAlias = spSurface;
				if (NULL_var != spAlias)
				{
					CATUnicodeString strAlias = spAlias->GetAlias();
					pMultiList->SetColumnItem(0, strAlias, i);

					pMultiList->SetSelect(&i,1);
				}
			}
		}
	}
}

